  plugins: [react()],
  resolve: {
    alias: {
      '@': path.resolve(__dirname, './src'),
    },
  },
  server: {
    port: 5173,
    proxy: {
      '/api': 'http://localhost:3001',
    },
  },
})

/** @type {import('tailwindcss').Config} */
export default {
  darkMode: ['class'],
  content: ['./index.html', './src/**/*.{ts,tsx}'],
  theme: {
    extend: {
      colors: {
        brand: {
          50: '#eef2ff',
          100: '#e0e7ff',
          200: '#c7d2fe',
          300: '#a5b4fc',
          400: '#818cf8',
          500: '#6366f1',
          600: '#4f46e5',
          700: '#4338ca',
          800: '#3730a3',
          900: '#312e81',
          950: '#1e1b4b',
        },
      },
      borderRadius: {
        lg: 'var(--radius)',
        md: 'calc(var(--radius) - 2px)',
        sm: 'calc(var(--radius) - 4px)',
      },
      fontFamily: {
        sans: ['Inter', 'system-ui', 'sans-serif'],
      },
    },
  },
  plugins: [require('tailwindcss-animate')],
}

export default {
  plugins: {
    tailwindcss: {},
    autoprefixer: {},
  },
}

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --radius: 0.625rem;
  --background: #ffffff;
  --foreground: #0f172a;
  --card: #ffffff;
  --card-foreground: #0f172a;
  --popover: #ffffff;
  --popover-foreground: #0f172a;
  --primary: #4f46e5;
  --primary-foreground: #f8fafc;
  --secondary: #f1f5f9;
  --secondary-foreground: #1e293b;
  --muted: #f1f5f9;
  --muted-foreground: #64748b;
  --accent: #f1f5f9;
  --accent-foreground: #1e293b;
  --destructive: #ef4444;
  --destructive-foreground: #f8fafc;
  --success: #22c55e;
  --success-foreground: #f8fafc;
  --border: #e2e8f0;
  --input: #e2e8f0;
  --ring: #4f46e5;
}

@layer base {
  * {
    @apply border-border;
  }
  body {
    @apply bg-background text-foreground;
    font-feature-settings: "rlig" 1, "calt" 1;
  }
}

@layer components {
  .gradient-brand {
    @apply bg-gradient-to-br from-brand-500 via-brand-600 to-indigo-700;
  }
  .gradient-brand-subtle {
    @apply bg-gradient-to-br from-brand-50 to-indigo-50;
  }
}

.animate-in {
  animation: fadeInUp 0.5s ease-out;
}

@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(12px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes slideIn {
  from {
    opacity: 0;
    transform: translateX(-12px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

.slide-in {
  animation: slideIn 0.3s ease-out;
}

@keyframes pulse-dot {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.4; }
}

.pulse-dot {
  animation: pulse-dot 1.5s ease-in-out infinite;
}

import { clsx, type ClassValue } from 'clsx'
import { twMerge } from 'tailwind-merge'

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

export interface LessonPlan {
  title: string
  difficulty: 'beginner' | 'intermediate' | 'advanced'
  objectives: Objective[]
}

export interface Objective {
  id: string
  title: string
  description: string
}

export interface McqChoice {
  id: string
  text: string
}

export interface McqQuestion {
  id: string
  objectiveId: string
  question: string
  choices: McqChoice[]
  correctChoiceId: string
  explanation: string
  hint: string
}

export interface McqResult {
  questionId: string
  objectiveId: string
  selectedChoiceId: string | null
  correct: boolean
  attempts: number
  completedAt?: string
}

export interface ProgressReport {
  totalQuestions: number
  correctFirstTry: number
  correctTotal: number
  totalAttempts: number
  objectiveResults: {
    objectiveId: string
    title: string
    total: number
    correct: number
    attempts: number
  }[]
  studyTips: string[]
  summary: string
}

export type AppState =
  | { phase: 'upload' }
  | { phase: 'planning'; pdfContent: string; fileName: string }
  | { phase: 'approval'; plan: LessonPlan; pdfContent: string; fileName: string }
  | { phase: 'learning'; plan: LessonPlan; questions: McqQuestion[]; pdfContent: string }
  | { phase: 'completed'; report: ProgressReport; plan: LessonPlan }

import Database from 'better-sqlite3'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const dbPath = path.join(__dirname, '..', 'data', 'learning.db')

let db: Database.Database

export function getDb(): Database.Database {
  if (!db) {
    db = new Database(dbPath)
    db.pragma('journal_mode = WAL')
    initSchema()
  }
  return db
}

function initSchema() {
  const d = getDb()
  d.exec(`
    CREATE TABLE IF NOT EXISTS lessons (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      file_name TEXT NOT NULL,
      title TEXT NOT NULL,
      difficulty TEXT NOT NULL,
      content TEXT NOT NULL,
      plan_json TEXT NOT NULL,
      created_at TEXT DEFAULT (datetime('now'))
    );

    CREATE TABLE IF NOT EXISTS questions (
      id TEXT PRIMARY KEY,
      lesson_id INTEGER NOT NULL,
      objective_id TEXT NOT NULL,
      question_json TEXT NOT NULL,
      FOREIGN KEY (lesson_id) REFERENCES lessons(id)
    );

    CREATE TABLE IF NOT EXISTS results (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      lesson_id INTEGER NOT NULL,
      question_id TEXT NOT NULL,
      objective_id TEXT NOT NULL,
      selected_choice_id TEXT,
      correct INTEGER NOT NULL DEFAULT 0,
      attempts INTEGER NOT NULL DEFAULT 1,
      completed_at TEXT,
      FOREIGN KEY (lesson_id) REFERENCES lessons(id)
    );

    CREATE TABLE IF NOT EXISTS feedback (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      lesson_id INTEGER NOT NULL,
      question_id TEXT NOT NULL,
      user_message TEXT NOT NULL,
      agent_response TEXT NOT NULL,
      created_at TEXT DEFAULT (datetime('now')),
      FOREIGN KEY (lesson_id) REFERENCES lessons(id)
    );
  `)
}

export function saveLesson(data: {
  fileName: string
  title: string
  difficulty: string
  content: string
  planJson: string
}): number {
  const d = getDb()
  const stmt = d.prepare(
    'INSERT INTO lessons (file_name, title, difficulty, content, plan_json) VALUES (?, ?, ?, ?, ?)'
  )
  const result = stmt.run(data.fileName, data.title, data.difficulty, data.content, data.planJson)
  return Number(result.lastInsertRowid)
}

export function saveQuestions(lessonId: number, questions: Array<{
  id: string
  objectiveId: string
  questionJson: string
}>) {
  const d = getDb()
  const stmt = d.prepare(
    'INSERT OR REPLACE INTO questions (id, lesson_id, objective_id, question_json) VALUES (?, ?, ?, ?)'
  )
  const insertMany = d.transaction((items: typeof questions) => {
    for (const q of items) {
      stmt.run(q.id, lessonId, q.objectiveId, q.questionJson)
    }
  })
  insertMany(questions)
}

export function saveResult(data: {
  lessonId: number
  questionId: string
  objectiveId: string
  selectedChoiceId: string | null
  correct: boolean
  attempts: number
  completedAt?: string
}) {
  const d = getDb()
  const stmt = d.prepare(
    `INSERT INTO results (lesson_id, question_id, objective_id, selected_choice_id, correct, attempts, completed_at)
     VALUES (?, ?, ?, ?, ?, ?, ?)`
  )
  stmt.run(
    data.lessonId,
    data.questionId,
    data.objectiveId,
    data.selectedChoiceId,
    data.correct ? 1 : 0,
    data.attempts,
    data.completedAt ?? null
  )
}

export function getResultsForLesson(lessonId: number) {
  const d = getDb()
  return d.prepare('SELECT * FROM results WHERE lesson_id = ? ORDER BY id').all(lessonId)
}

export function saveFeedback(data: {
  lessonId: number
  questionId: string
  userMessage: string
  agentResponse: string
}) {
  const d = getDb()
  const stmt = d.prepare(
    'INSERT INTO feedback (lesson_id, question_id, user_message, agent_response) VALUES (?, ?, ?, ?)'
  )
  stmt.run(data.lessonId, data.questionId, data.userMessage, data.agentResponse)
}

import OpenAI from 'openai'
import type { LessonPlan, McqQuestion, ProgressReport, Objective } from '../src/lib/types'

const openai = new OpenAI({
  apiKey: process.env.OPENAI_API_KEY,
})

export async function generateLessonPlan(pdfContent: string): Promise<LessonPlan> {
  const prompt = `You are an expert educational designer. Analyze the following content from a PDF document and create a structured lesson plan.

Content:
${pdfContent.slice(0, 15000)}

Create a lesson plan with:
1. A concise title for the lesson
2. A difficulty level: "beginner", "intermediate", or "advanced"
3. 3-5 learning objectives, each with a unique id, title, and a one-sentence description

Respond ONLY with a valid JSON object in this exact format:
{
  "title": "string",
  "difficulty": "beginner|intermediate|advanced",
  "objectives": [
    { "id": "obj-1", "title": "string", "description": "string" }
  ]
}`

  const response = await openai.chat.completions.create({
    model: process.env.OPENAI_MODEL ?? 'gpt-4o',
    messages: [{ role: 'user', content: prompt }],
    response_format: { type: 'json_object' },
    temperature: 0.3,
  })

  const content = response.choices[0]?.message?.content
  if (!content) throw new Error('No response from LLM')

  const plan = JSON.parse(content) as LessonPlan
  return plan
}

export async function generateMcqs(
  pdfContent: string,
  objectives: Objective[]
): Promise<McqQuestion[]> {
  const objectivesStr = objectives
    .map((o) => `- ${o.id}: ${o.title} - ${o.description}`)
    .join('\n')

  const prompt = `You are an expert quiz designer. Based on the following PDF content and learning objectives, create multiple-choice questions.

PDF Content:
${pdfContent.slice(0, 15000)}

Learning Objectives:
${objectivesStr}

Create 2-3 multiple-choice questions PER objective. Each question must:
- Be directly answerable from the PDF content
- Have exactly 4 choices
- Include the correct answer ID
- Include a detailed explanation for the correct answer
- Include a helpful hint for incorrect answers (don't give away the answer, guide the learner)

Respond ONLY with a valid JSON array in this exact format:
[
  {
    "id": "q-1",
    "objectiveId": "obj-1",
    "question": "string",
    "choices": [
      { "id": "a", "text": "string" },
      { "id": "b", "text": "string" },
      { "id": "c", "text": "string" },
      { "id": "d", "text": "string" }
    ],
    "correctChoiceId": "a",
    "explanation": "string explaining why this is correct",
    "hint": "string giving a nudge without revealing the answer"
  }
]`

  const response = await openai.chat.completions.create({
    model: process.env.OPENAI_MODEL ?? 'gpt-4o',
    messages: [{ role: 'user', content: prompt }],
    response_format: { type: 'json_object' },
    temperature: 0.5,
  })

  const content = response.choices[0]?.message?.content
  if (!content) throw new Error('No response from LLM')

  const parsed = JSON.parse(content)
  const questions: McqQuestion[] = Array.isArray(parsed)
    ? parsed
    : parsed.questions ?? []

  return questions
}

export async function getHint(
  pdfContent: string,
  question: McqQuestion,
  userAttempts: number
): Promise<string> {
  const prompt = `A learner is struggling with this question (${userAttempts} attempt(s) so far):

Question: ${question.question}
Choices: ${question.choices.map((c) => `${c.id}) ${c.text}`).join(', ')}
Correct answer: ${question.correctChoiceId}

Relevant content:
${pdfContent.slice(0, 5000)}

DO NOT reveal the correct answer. Provide a helpful nudge or rephrase the concept that will guide the learner toward the correct answer. Keep it under 3 sentences.`

  const response = await openai.chat.completions.create({
    model: process.env.OPENAI_MODEL ?? 'gpt-4o',
    messages: [{ role: 'user', content: prompt }],
    temperature: 0.7,
  })

  return response.choices[0]?.message?.content ?? "Think about the key concepts we just covered."
}

export async function generateReport(
  objectives: Objective[],
  results: Array<{
    questionId: string
    objectiveId: string
    correct: boolean
    attempts: number
  }>,
  totalQuestions: number
): Promise<ProgressReport> {
  const correctFirstTry = results.filter((r) => r.correct && r.attempts === 1).length
  const correctTotal = results.filter((r) => r.correct).length
  const totalAttempts = results.reduce((sum, r) => sum + r.attempts, 0)

  const objectiveResults = objectives.map((obj) => {
    const objRes = results.filter((r) => r.objectiveId === obj.id)
    return {
      objectiveId: obj.id,
      title: obj.title,
      total: objRes.length,
      correct: objRes.filter((r) => r.correct).length,
      attempts: objRes.reduce((sum, r) => sum + r.attempts, 0),
    }
  })

  const resultsSummary = objectiveResults
    .map(
      (o) =>
        `- ${o.title}: ${o.correct}/${o.total} correct, ${o.attempts} total attempts (${o.correct === o.total ? 'Mastered' : o.correct >= o.total / 2 ? 'Progressing' : 'Needs Review'})`
    )
    .join('\n')

  const prompt = `Based on the following quiz results, generate a personalized progress report with study tips.

Results:
${resultsSummary}

Total questions: ${totalQuestions}
Correct on first try: ${correctFirstTry}
Total correct: ${correctTotal}

Provide:
1. A brief summary paragraph (2-3 sentences) of overall performance
2. Three specific, actionable study tips for improvement

Respond ONLY with a valid JSON object:
{
  "summary": "string",
  "studyTips": ["tip1", "tip2", "tip3"]
}`

  const response = await openai.chat.completions.create({
    model: process.env.OPENAI_MODEL ?? 'gpt-4o',
    messages: [{ role: 'user', content: prompt }],
    response_format: { type: 'json_object' },
    temperature: 0.7,
  })

  const content = response.choices[0]?.message?.content
  if (!content) throw new Error('No response from LLM')

  const parsed = JSON.parse(content)

  return {
    totalQuestions,
    correctFirstTry,
    correctTotal,
    totalAttempts,
    objectiveResults,
    studyTips: parsed.studyTips ?? [],
    summary: parsed.summary ?? '',
  }
}

import express from 'express'
import cors from 'cors'
import multer from 'multer'
import path from 'node:path'
import { fileURLToPath } from 'node:url'
import { execFileSync } from 'node:child_process'
import fs from 'node:fs'
import { getDb, saveLesson, saveQuestions, saveResult, saveFeedback } from '../src/lib/db'
import {
  generateLessonPlan,
  generateMcqs,
  getHint,
  generateReport,
} from './agent'
import type { McqQuestion } from '../src/lib/types'

const __dirname = path.dirname(fileURLToPath(import.meta.url))

const app = express()
const PORT = Number(process.env.PORT) || 3001

app.use(cors())
app.use(express.json({ limit: '50mb' }))

const uploadsDir = path.join(__dirname, '..', 'data', 'uploads')
const markdownDir = path.join(__dirname, '..', 'data', 'markdown')
fs.mkdirSync(uploadsDir, { recursive: true })
fs.mkdirSync(markdownDir, { recursive: true })

const pdfToMarkdownScript = path.join(__dirname, '..', 'pdf-to-markdown', 'convert-docling.py')

const storage = multer.diskStorage({
  destination: uploadsDir,
  filename: (_req, file, cb) => {
    const unique = Date.now() + '-' + Math.round(Math.random() * 1e9)
    cb(null, unique + '-' + file.originalname)
  },
})
const upload = multer({ storage, limits: { fileSize: 50 * 1024 * 1024 } })

app.post('/api/upload', upload.single('pdf'), async (req, res) => {
  try {
    const file = req.file
    if (!file) {
      res.status(400).json({ error: 'No PDF file uploaded' })
      return
    }

    const inputPath = file.path
    const outputName = path.basename(file.originalname, '.pdf') + '.md'
    const outputPath = path.join(markdownDir, outputName)

    try {
      execFileSync('python3', [pdfToMarkdownScript, '--input', inputPath, '--output', outputPath], {
        timeout: 120000,
      })
    } catch (e: unknown) {
      const errMsg = e instanceof Error ? e.message : String(e)
      console.error('PDF conversion failed:', errMsg)
      res.status(500).json({ error: 'Failed to convert PDF to markdown' })
      return
    }

    if (!fs.existsSync(outputPath)) {
      res.status(500).json({ error: 'Markdown file was not created' })
      return
    }

    const pdfContent = fs.readFileSync(outputPath, 'utf-8')

    res.json({
      fileName: file.originalname,
      pdfContent,
    })
  } catch (e: unknown) {
    const errMsg = e instanceof Error ? e.message : String(e)
    console.error('Upload error:', errMsg)
    res.status(500).json({ error: 'Upload failed' })
  }
})

app.post('/api/plan', async (req, res) => {
  try {
    const { pdfContent } = req.body as { pdfContent: string }
    if (!pdfContent) {
      res.status(400).json({ error: 'No content provided' })
      return
    }

    const plan = await generateLessonPlan(pdfContent)
    res.json({ plan })
  } catch (e: unknown) {
    const errMsg = e instanceof Error ? e.message : String(e)
    console.error('Plan error:', errMsg)
    res.status(500).json({ error: 'Failed to generate lesson plan' })
  }
})

app.post('/api/mcqs', async (req, res) => {
  try {
    const { pdfContent, plan, fileName } = req.body as {
      pdfContent: string
      plan: { title: string; difficulty: string; objectives: { id: string; title: string; description: string }[] }
      fileName: string
    }
    if (!pdfContent || !plan) {
      res.status(400).json({ error: 'No content or plan provided' })
      return
    }

    const questions = await generateMcqs(pdfContent, plan.objectives)

    const lessonId = saveLesson({
      fileName,
      title: plan.title,
      difficulty: plan.difficulty,
      content: pdfContent,
      planJson: JSON.stringify(plan),
    })

    saveQuestions(
      lessonId,
      questions.map((q: McqQuestion) => ({
        id: q.id,
        objectiveId: q.objectiveId,
        questionJson: JSON.stringify(q),
      }))
    )

    res.json({ questions, lessonId })
  } catch (e: unknown) {
    const errMsg = e instanceof Error ? e.message : String(e)
    console.error('MCQ error:', errMsg)
    res.status(500).json({ error: 'Failed to generate questions' })
  }
})

app.post('/api/hint', async (req, res) => {
  try {
    const { pdfContent, question, attempts } = req.body as {
      pdfContent: string
      question: McqQuestion
      attempts: number
    }

    const hint = await getHint(pdfContent, question, attempts)
    res.json({ hint })
  } catch (e: unknown) {
    const errMsg = e instanceof Error ? e.message : String(e)
    console.error('Hint error:', errMsg)
    res.status(500).json({ error: 'Failed to generate hint' })
  }
})

app.post('/api/result', async (req, res) => {
  try {
    const { lessonId, questionId, objectiveId, selectedChoiceId, correct, attempts, completedAt } = req.body

    saveResult({
      lessonId,
      questionId,
      objectiveId,
      selectedChoiceId,
      correct,
      attempts,
      completedAt,
    })

    res.json({ ok: true })
  } catch (e: unknown) {
    const errMsg = e instanceof Error ? e.message : String(e)
    console.error('Result error:', errMsg)
    res.status(500).json({ error: 'Failed to save result' })
  }
})

app.post('/api/report', async (req, res) => {
  try {
    const { objectives, results, totalQuestions } = req.body

    const report = await generateReport(objectives, results, totalQuestions)
    res.json({ report })
  } catch (e: unknown) {
    const errMsg = e instanceof Error ? e.message : String(e)
    console.error('Report error:', errMsg)
    res.status(500).json({ error: 'Failed to generate report' })
  }
})

app.post('/api/feedback', async (req, res) => {
  try {
    const { lessonId, questionId, userMessage, agentResponse } = req.body
    saveFeedback({ lessonId, questionId, userMessage, agentResponse })
    res.json({ ok: true })
  } catch (e: unknown) {
    const errMsg = e instanceof Error ? e.message : String(e)
    console.error('Feedback error:', errMsg)
    res.status(500).json({ error: 'Failed to save feedback' })
  }
})

app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`)
})

