import { useCallback, useState } from 'react'
import { Upload, FileText, Loader2 } from 'lucide-react'
import { Button } from '@/components/ui/Button'

interface PdfUploadProps {
  onUpload: (pdfContent: string, fileName: string) => void
}

export function PdfUpload({ onUpload }: PdfUploadProps) {
  const [dragOver, setDragOver] = useState(false)
  const [uploading, setUploading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const handleFile = useCallback(
    async (file: File) => {
      if (!file.name.endsWith('.pdf')) {
        setError('Please upload a PDF file')
        return
      }

      setError(null)
      setUploading(true)

      try {
        const formData = new FormData()
        formData.append('pdf', file)

        const res = await fetch('/api/upload', { method: 'POST', body: formData })
        if (!res.ok) {
          const data = await res.json()
          throw new Error(data.error ?? 'Upload failed')
        }

        const data = await res.json()
        onUpload(data.pdfContent, data.fileName)
      } catch (e: unknown) {
        const msg = e instanceof Error ? e.message : 'Upload failed'
        setError(msg)
      } finally {
        setUploading(false)
      }
    },
    [onUpload]
  )

  const onDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault()
      setDragOver(false)
      const file = e.dataTransfer.files[0]
      if (file) handleFile(file)
    },
    [handleFile]
  )

  return (
    <div className="flex min-h-screen flex-col items-center justify-center px-4">
      <div className="w-full max-w-xl text-center">
        <div className="mb-8">
          <div className="mx-auto mb-6 flex size-20 items-center justify-center rounded-2xl gradient-brand shadow-lg shadow-brand-500/25">
            <FileText className="size-10 text-white" />
          </div>
          <h1 className="text-3xl font-bold tracking-tight text-slate-900">
            Upload Your Study Material
          </h1>
          <p className="mt-2 text-slate-500">
            Upload a PDF and our AI will transform it into an interactive lesson
          </p>
        </div>

        <div
          onDrop={onDrop}
          onDragOver={(e) => {
            e.preventDefault()
            setDragOver(true)
          }}
          onDragLeave={() => setDragOver(false)}
          className={`
            relative rounded-2xl border-2 border-dashed p-12 transition-all
            ${dragOver
              ? 'border-brand-500 bg-brand-50 scale-[1.02]'
              : 'border-slate-200 bg-white hover:border-brand-300 hover:bg-brand-50/30'
            }
          `}
        >
          {uploading ? (
            <div className="flex flex-col items-center gap-3">
              <Loader2 className="size-10 animate-spin text-brand-500" />
              <p className="text-sm font-medium text-slate-600">
                Converting PDF and extracting content...
              </p>
            </div>
          ) : (
            <>
              <Upload className="mx-auto mb-4 size-10 text-slate-300" />
              <p className="mb-1 font-medium text-slate-700">
                Drop your PDF here or click to browse
              </p>
              <p className="mb-6 text-sm text-slate-400">PDF files only, up to 50MB</p>
              <label>
                <Button as-child>
                  <span className="cursor-pointer">Choose File</span>
                </Button>
                <input
                  type="file"
                  accept=".pdf"
                  className="hidden"
                  onChange={(e) => {
                    const file = e.target.files?.[0]
                    if (file) handleFile(file)
                    e.target.value = ''
                  }}
                />
              </label>
            </>
          )}
        </div>

        {error && (
          <div className="mt-4 rounded-lg bg-red-50 px-4 py-3 text-sm text-red-600">
            {error}
          </div>
        )}

        <div className="mt-8 flex items-center justify-center gap-6 text-xs text-slate-400">
          <span className="flex items-center gap-1.5">
            <div className="size-1.5 rounded-full bg-emerald-400" />
            AI-Powered
          </span>
          <span className="flex items-center gap-1.5">
            <div className="size-1.5 rounded-full bg-brand-400" />
            Interactive Quizzes
          </span>
          <span className="flex items-center gap-1.5">
            <div className="size-1.5 rounded-full bg-amber-400" />
            Personalized Feedback
          </span>
        </div>
      </div>
    </div>
  )
}

import { useState, useCallback } from 'react'
import type { McqQuestion, McqResult } from '@/lib/types'
import { Button } from '@/components/ui/Button'
import { RadioGroup, RadioGroupItem } from '@/components/ui/RadioGroup'
import { Progress } from '@/components/ui/Progress'
import {
  CheckCircle2,
  XCircle,
  Lightbulb,
  ArrowRight,
  BookOpen,
  HelpCircle,
  ChevronRight,
  Target,
} from 'lucide-react'

interface McqWidgetProps {
  questions: McqQuestion[]
  plan: { objectives: { id: string; title: string }[] }
  onComplete: (results: McqResult[]) => void
  onGetHint: (question: McqQuestion, attempts: number) => Promise<string>
}

type QuestionState = {
  selectedChoice: string | null
  submitted: boolean
  correct: boolean | null
  explanation: string | null
  hint: string | null
  attempts: number
  hintLoading: boolean
}

export function McqWidget({ questions, plan, onComplete, onGetHint }: McqWidgetProps) {
  const [currentIndex, setCurrentIndex] = useState(0)
  const [results, setResults] = useState<McqResult[]>([])
  const [questionStates, setQuestionStates] = useState<Record<string, QuestionState>>({})

  const currentQuestion = questions[currentIndex]
  const currentState = questionStates[currentQuestion?.id] ?? {
    selectedChoice: null,
    submitted: false,
    correct: null,
    explanation: null,
    hint: null,
    attempts: 0,
    hintLoading: false,
  }

  const currentObjective = plan.objectives.find(
    (o) => o.id === currentQuestion?.objectiveId
  )

  const progress = questions.length > 0
    ? ((currentIndex + (currentState.submitted ? 1 : 0)) / questions.length) * 100
    : 0

  const setState = useCallback(
    (updates: Partial<QuestionState>) => {
      setQuestionStates((prev) => ({
        ...prev,
        [currentQuestion.id]: { ...prev[currentQuestion.id], ...updates },
      }))
    },
    [currentQuestion.id]
  )

  const handleSubmit = useCallback(() => {
    if (!currentState.selectedChoice || currentState.submitted) return

    const correct = currentState.selectedChoice === currentQuestion.correctChoiceId
    const attempts = currentState.attempts + 1

    if (correct) {
      setState({
        submitted: true,
        correct: true,
        explanation: currentQuestion.explanation,
        hint: null,
        attempts,
        selectedChoice: currentState.selectedChoice,
      })
    } else {
      setState({
        submitted: true,
        correct: false,
        explanation: null,
        hint: currentQuestion.hint,
        attempts,
        selectedChoice: currentState.selectedChoice,
      })
    }

    const newResult: McqResult = {
      questionId: currentQuestion.id,
      objectiveId: currentQuestion.objectiveId,
      selectedChoiceId: currentState.selectedChoice,
      correct,
      attempts,
      completedAt: correct ? new Date().toISOString() : undefined,
    }

    setResults((prev) => {
      const filtered = prev.filter((r) => r.questionId !== currentQuestion.id)
      return [...filtered, newResult]
    })
  }, [currentState, currentQuestion, setState])

  const handleRetry = useCallback(() => {
    setState({
      submitted: false,
      correct: null,
      explanation: null,
      hint: null,
      selectedChoice: null,
      hintLoading: false,
      attempts: currentState.attempts,
    })
  }, [currentState.attempts, setState])

  const handleNext = useCallback(() => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex((prev) => prev + 1)
    } else {
      onComplete(results)
    }
  }, [currentIndex, questions.length, results, onComplete])

  const handleGetHint = useCallback(async () => {
    setState({ hintLoading: true })
    try {
      const hint = await onGetHint(currentQuestion, currentState.attempts)
      setState({ hint, hintLoading: false })
    } catch {
      setState({ hintLoading: false })
    }
  }, [currentQuestion, currentState.attempts, onGetHint, setState])

  if (!currentQuestion) return null

  return (
    <div className="mx-auto max-w-3xl px-4 py-12">
      <div className="mb-8">
        <div className="mb-2 flex items-center justify-between text-sm">
          <span className="font-medium text-slate-500">
            Question {currentIndex + 1} of {questions.length}
          </span>
          <span className="text-slate-400">
            {Math.round(progress)}% complete
          </span>
        </div>
        <Progress value={progress} className="h-2" />
      </div>

      {currentObjective && (
        <div className="mb-4 inline-flex items-center gap-2 rounded-full bg-brand-50 px-3 py-1 text-xs font-medium text-brand-700">
          <Target className="size-3" />
          {currentObjective.title}
        </div>
      )}

      <div className="mb-8 animate-in">
        <h2 className="text-xl font-semibold leading-relaxed text-slate-900">
          {currentQuestion.question}
        </h2>
      </div>

      <RadioGroup
        value={currentState.submitted ? currentState.selectedChoice ?? '' : currentState.selectedChoice ?? ''}
        onValueChange={(val) => {
          if (!currentState.submitted) setState({ selectedChoice: val })
        }}
        className="mb-6"
        disabled={currentState.submitted}
      >
        {currentQuestion.choices.map((choice) => {
          let variant: 'default' | 'correct' | 'incorrect' = 'default'
          if (currentState.submitted) {
            if (choice.id === currentQuestion.correctChoiceId) {
              variant = 'correct'
            } else if (choice.id === currentState.selectedChoice && !currentState.correct) {
              variant = 'incorrect'
            }
          }
          return (
            <RadioGroupItem key={choice.id} value={choice.id} variant={variant}>
              <span className="text-sm font-medium">{choice.text}</span>
            </RadioGroupItem>
          )
        })}
      </RadioGroup>

      {currentState.submitted && currentState.correct && (
        <div className="mb-6 animate-in rounded-xl border border-emerald-200 bg-emerald-50 p-5">
          <div className="mb-2 flex items-center gap-2">
            <CheckCircle2 className="size-5 text-emerald-600" />
            <span className="font-semibold text-emerald-800">Correct!</span>
          </div>
          <p className="text-sm leading-relaxed text-emerald-700">
            {currentState.explanation}
          </p>
        </div>
      )}

      {currentState.submitted && currentState.correct === false && (
        <div className="mb-6 animate-in rounded-xl border border-red-200 bg-red-50 p-5">
          <div className="mb-2 flex items-center gap-2">
            <XCircle className="size-5 text-red-500" />
            <span className="font-semibold text-red-700">Not quite!</span>
          </div>
          <div className="mb-3 flex items-start gap-2">
            <Lightbulb className="mt-0.5 size-4 shrink-0 text-amber-500" />
            <p className="text-sm leading-relaxed text-red-600">
              {currentState.hint}
            </p>
          </div>
          <div className="flex flex-wrap gap-2">
            <Button size="sm" onClick={handleRetry}>
              Try Again
            </Button>
            <Button
              size="sm"
              variant="ghost"
              onClick={handleGetHint}
              loading={currentState.hintLoading}
            >
              <HelpCircle className="size-4" />
              Learn More
            </Button>
          </div>
        </div>
      )}

      <div className="flex items-center justify-between border-t border-slate-100 pt-6">
        <div />
        <div className="flex gap-3">
          {currentState.submitted && currentState.correct ? (
            <Button size="lg" onClick={handleNext}>
              {currentIndex < questions.length - 1 ? (
                <>
                  Next Question
                  <ArrowRight className="size-4" />
                </>
              ) : (
                <>
                  See Results
                  <ChevronRight className="size-4" />
                </>
              )}
            </Button>
          ) : !currentState.submitted ? (
            <Button
              size="lg"
              onClick={handleSubmit}
              disabled={!currentState.selectedChoice}
            >
              Submit Answer
            </Button>
          ) : null}
        </div>
      </div>

      <div className="mt-8">
        <div className="flex flex-wrap gap-2">
          {questions.map((q, i) => {
            const rs = questionStates[q.id]
            const res = results.find((r) => r.questionId === q.id)
            const isCorrect = res?.correct
            const isAttempted = rs?.submitted
            const isCurrent = i === currentIndex

            return (
              <div
                key={q.id}
                className={`
                  flex size-8 items-center justify-center rounded-lg text-xs font-medium transition-all
                  ${isCurrent && !isAttempted
                    ? 'bg-brand-500 text-white shadow-sm'
                    : isCorrect
                    ? 'bg-emerald-100 text-emerald-700'
                    : isAttempted && !isCorrect
                    ? 'bg-red-100 text-red-700'
                    : 'bg-slate-100 text-slate-400'
                  }
                  ${isCurrent ? 'ring-2 ring-brand-300 ring-offset-2' : ''}
                `}
              >
                {i + 1}
              </div>
            )
          })}
        </div>
      </div>
    </div>
  )
}

import { useState, useCallback } from 'react'
import type { AppState, LessonPlan, McqQuestion, McqResult, ProgressReport } from '@/lib/types'
import { PdfUpload } from '@/components/PdfUpload'
import { LessonPlanView, PlanningScreen } from '@/components/LessonPlan'
import { McqWidget } from '@/components/McqWidget'
import { ProgressReportView, GeneratingScreen } from '@/components/ProgressReport'

export default function App() {
  const [state, setState] = useState<AppState>({ phase: 'upload' })
  const [planLoading, setPlanLoading] = useState(false)
  const [mcqLoading, setMcqLoading] = useState(false)
  const [lessonId, setLessonId] = useState<number | null>(null)

  const handleUpload = useCallback(async (pdfContent: string, fileName: string) => {
    setState({ phase: 'planning', pdfContent, fileName })
    setPlanLoading(true)

    try {
      const res = await fetch('/api/plan', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ pdfContent }),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error)
      setState({ phase: 'approval', plan: data.plan, pdfContent, fileName })
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : 'Failed'
      console.error('Plan error:', msg)
      setState({ phase: 'upload' })
    } finally {
      setPlanLoading(false)
    }
  }, [])

  const handleRegenerate = useCallback(async () => {
    if (state.phase !== 'approval') return
    setPlanLoading(true)
    try {
      const res = await fetch('/api/plan', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ pdfContent: state.pdfContent }),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error)
      setState({ phase: 'approval', plan: data.plan, pdfContent: state.pdfContent, fileName: state.fileName })
    } catch (e: unknown) {
      console.error('Regenerate error:', e)
    } finally {
      setPlanLoading(false)
    }
  }, [state])

  const handleApprove = useCallback(async () => {
    if (state.phase !== 'approval') return
    setMcqLoading(true)

    try {
      const res = await fetch('/api/mcqs', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          pdfContent: state.pdfContent,
          plan: state.plan,
          fileName: state.fileName,
        }),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error)
      setLessonId(data.lessonId)
      setState({
        phase: 'learning',
        plan: state.plan,
        questions: data.questions,
        pdfContent: state.pdfContent,
      })
    } catch (e: unknown) {
      console.error('MCQ error:', e)
    } finally {
      setMcqLoading(false)
    }
  }, [state])

  const handleComplete = useCallback(
    async (results: McqResult[]) => {
      if (state.phase !== 'learning') return

      setState({
        phase: 'completed',
        report: {
          totalQuestions: 0,
          correctFirstTry: 0,
          correctTotal: 0,
          totalAttempts: 0,
          objectiveResults: [],
          studyTips: [],
          summary: '',
        },
        plan: state.plan,
      })

      try {
        for (const r of results) {
          await fetch('/api/result', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              lessonId,
              questionId: r.questionId,
              objectiveId: r.objectiveId,
              selectedChoiceId: r.selectedChoiceId,
              correct: r.correct,
              attempts: r.attempts,
              completedAt: r.completedAt,
            }),
          })
        }

        const res = await fetch('/api/report', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            objectives: state.plan.objectives,
            results,
            totalQuestions: state.questions.length,
          }),
        })
        const data = await res.json()
        if (!res.ok) throw new Error(data.error)

        setState({
          phase: 'completed',
          report: data.report,
          plan: state.plan,
        })
      } catch (e: unknown) {
        console.error('Report error:', e)
      }
    },
    [state, lessonId]
  )

  const handleGetHint = useCallback(
    async (question: McqQuestion, attempts: number): Promise<string> => {
      if (state.phase !== 'learning') return ''

      try {
        const res = await fetch('/api/hint', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            pdfContent: state.pdfContent,
            question,
            attempts,
          }),
        })
        const data = await res.json()
        return data.hint ?? ''
      } catch {
        return 'Try reviewing the relevant section of the material.'
      }
    },
    [state]
  )

  const restart = useCallback(() => {
    setState({ phase: 'upload' })
    setLessonId(null)
  }, [])

  switch (state.phase) {
    case 'upload':
      return <PdfUpload onUpload={handleUpload} />

    case 'planning':
      return <PlanningScreen fileName={state.fileName} />

    case 'approval':
      return (
        <LessonPlanView
          plan={state.plan}
          fileName={state.fileName}
          loading={planLoading}
          onApprove={handleApprove}
          onRegenerate={handleRegenerate}
        />
      )

    case 'learning':
      return mcqLoading ? (
        <GeneratingScreen />
      ) : (
        <McqWidget
          questions={state.questions}
          plan={state.plan}
          onComplete={handleComplete}
          onGetHint={handleGetHint}
        />
      )

    case 'completed':
      return (
        <ProgressReportView
          report={state.report}
          plan={state.plan}
          onRestart={restart}
        />
      )

    default:
      return <PdfUpload onUpload={handleUpload} />
  }
}

