import OpenAI from 'openai'
import type { LessonPlan, McqQuestion, ProgressReport, Objective } from '../src/lib/types'

const openai = new OpenAI({
  apiKey: process.env.OPENAI_API_KEY,
})

export async function generateLessonPlan(pdfContent: string): Promise<LessonPlan> {
  const prompt = `You are an expert educational designer. Analyze the following content from a PDF document and create a structured lesson plan.

Content:
${pdfContent.slice(0, 15000)}

Create a lesson plan with:
1. A concise title for the lesson
2. A difficulty level: "beginner", "intermediate", or "advanced"
3. 3-5 learning objectives, each with a unique id, title, and a one-sentence description

Respond ONLY with a valid JSON object in this exact format:
{
  "title": "string",
  "difficulty": "beginner|intermediate|advanced",
  "objectives": [
    { "id": "obj-1", "title": "string", "description": "string" }
  ]
}`

  const response = await openai.chat.completions.create({
    model: process.env.OPENAI_MODEL ?? 'gpt-4o',
    messages: [{ role: 'user', content: prompt }],
    response_format: { type: 'json_object' },
    temperature: 0.3,
  })

  const content = response.choices[0]?.message?.content
  if (!content) throw new Error('No response from LLM')

  const plan = JSON.parse(content) as LessonPlan
  return plan
}

export async function generateMcqs(
  pdfContent: string,
  objectives: Objective[]
): Promise<McqQuestion[]> {
  const objectivesStr = objectives
    .map((o) => `- ${o.id}: ${o.title} - ${o.description}`)
    .join('\n')

  const prompt = `You are an expert quiz designer. Based on the following PDF content and learning objectives, create multiple-choice questions.

PDF Content:
${pdfContent.slice(0, 15000)}

Learning Objectives:
${objectivesStr}

Create 2-3 multiple-choice questions PER objective. Each question must:
- Be directly answerable from the PDF content
- Have exactly 4 choices
- Include the correct answer ID
- Include a detailed explanation for the correct answer
- Include a helpful hint for incorrect answers (don't give away the answer, guide the learner)

Respond ONLY with a valid JSON array in this exact format:
[
  {
    "id": "q-1",
    "objectiveId": "obj-1",
    "question": "string",
    "choices": [
      { "id": "a", "text": "string" },
      { "id": "b", "text": "string" },
      { "id": "c", "text": "string" },
      { "id": "d", "text": "string" }
    ],
    "correctChoiceId": "a",
    "explanation": "string explaining why this is correct",
    "hint": "string giving a nudge without revealing the answer"
  }
]`

  const response = await openai.chat.completions.create({
    model: process.env.OPENAI_MODEL ?? 'gpt-4o',
    messages: [{ role: 'user', content: prompt }],
    response_format: { type: 'json_object' },
    temperature: 0.5,
  })

  const content = response.choices[0]?.message?.content
  if (!content) throw new Error('No response from LLM')

  const parsed = JSON.parse(content)
  const questions: McqQuestion[] = Array.isArray(parsed)
    ? parsed
    : parsed.questions ?? []

  return questions
}

export async function getHint(
  pdfContent: string,
  question: McqQuestion,
  userAttempts: number
): Promise<string> {
  const prompt = `A learner is struggling with this question (${userAttempts} attempt(s) so far):

Question: ${question.question}
Choices: ${question.choices.map((c) => `${c.id}) ${c.text}`).join(', ')}
Correct answer: ${question.correctChoiceId}

Relevant content:
${pdfContent.slice(0, 5000)}

DO NOT reveal the correct answer. Provide a helpful nudge or rephrase the concept that will guide the learner toward the correct answer. Keep it under 3 sentences.`

  const response = await openai.chat.completions.create({
    model: process.env.OPENAI_MODEL ?? 'gpt-4o',
    messages: [{ role: 'user', content: prompt }],
    temperature: 0.7,
  })

  return response.choices[0]?.message?.content ?? "Think about the key concepts we just covered."
}

export async function generateReport(
  objectives: Objective[],
  results: Array<{
    questionId: string
    objectiveId: string
    correct: boolean
    attempts: number
  }>,
  totalQuestions: number
): Promise<ProgressReport> {
  const correctFirstTry = results.filter((r) => r.correct && r.attempts === 1).length
  const correctTotal = results.filter((r) => r.correct).length
  const totalAttempts = results.reduce((sum, r) => sum + r.attempts, 0)

  const objectiveResults = objectives.map((obj) => {
    const objRes = results.filter((r) => r.objectiveId === obj.id)
    return {
      objectiveId: obj.id,
      title: obj.title,
      total: objRes.length,
      correct: objRes.filter((r) => r.correct).length,
      attempts: objRes.reduce((sum, r) => sum + r.attempts, 0),
    }
  })

  const resultsSummary = objectiveResults
    .map(
      (o) =>
        `- ${o.title}: ${o.correct}/${o.total} correct, ${o.attempts} total attempts (${o.correct === o.total ? 'Mastered' : o.correct >= o.total / 2 ? 'Progressing' : 'Needs Review'})`
    )
    .join('\n')

  const prompt = `Based on the following quiz results, generate a personalized progress report with study tips.

Results:
${resultsSummary}

Total questions: ${totalQuestions}
Correct on first try: ${correctFirstTry}
Total correct: ${correctTotal}

Provide:
1. A brief summary paragraph (2-3 sentences) of overall performance
2. Three specific, actionable study tips for improvement

Respond ONLY with a valid JSON object:
{
